sys_script_include.script:
var AgineoZipService = Class.create();
AgineoZipService.prototype = {



    createZip: function(files, targetGR, zipNameOpt) {
        try {
            if (!files || typeof files !== 'object') {
                gs.error('[AgineoZipService] files invalid');
                return;
            }
            if (!targetGR || !targetGR.isValidRecord()) {
                gs.error('[AgineoZipService] targetGR invalid');
                return;
            }

            // Build ZIP in memory (Global scope: Packages.* allowed)
            var baos = new Packages.java.io.ByteArrayOutputStream();
            var zos = new Packages.java.util.zip.ZipOutputStream(baos);

            var fileCount = 0;

            for (var path in files) {
                if (!files.hasOwnProperty(path)) continue;

                var content = (files[path] + '');

                var entry = new Packages.java.util.zip.ZipEntry(path);
                zos.putNextEntry(entry);

                var bytes = new Packages.java.lang.String(content).getBytes('UTF-8');
                zos.write(bytes, 0, bytes.length);
                zos.closeEntry();

                fileCount++;
            }

            zos.close();

            if (fileCount === 0) {
                gs.warn('[AgineoZipService] No files to zip');
                return;
            }

            var zipName = zipNameOpt || ('Validated_Expenses_' + gs.generateGUID() + '.zip');
            var zipBytes = baos.toByteArray();

            new GlideSysAttachment().write(
                targetGR,
                zipName,
                'application/zip',
                zipBytes
            );

            gs.info('[AgineoZipService] ZIP created: ' + zipName + ' | files=' + fileCount +
                ' | attached_to=' + targetGR.getTableName() + ':' + targetGR.getUniqueValue());

        } catch (e) {
            gs.error('[AgineoZipService] ERROR: ' + e);
            if (e && e.stack) gs.error(e.stack);
            throw e;
        }
    },

    type: 'AgineoZipService'
};
